                if (is_object($item)) {
                    $itemResult = $this->processSingleObject($item);
                    $results['processed'] += $itemResult['processed'];
                    $results['errors'] = array_merge($results['errors'], $itemResult['errors']);
                }
            } catch (Exception $e) {
                $results['errors'][] = $e->getMessage();
            }
        }
        
        return $results;
    }
    
