        $stmt->execute();
    }
    
    private function insertProduct($product) {
        $stmt = $this->db->prepare('INSERT OR REPLACE INTO products (id, name, price, category) VALUES (:id, :name, :price, :category)');
        $stmt->bindValue(':id', $product->id, SQLITE3_INTEGER);
